import base64
import requests
import xml.etree.ElementTree as ET
from urllib.parse import urlencode

class SAMLServiceProvider:
    def __init__(self, destination_url):
        self.destination_url = destination_url

    def build_authn_request(self, user_info):
        request_id = f"request_id_{user_info['username']}"
        issuer = "your_issuer"
        name_id = user_info['username']
        
        saml_request = f"""<?xml version="1.0" encoding="UTF-8"?>
        <s:Envelope xmlns:s="http://schemas.xmlsoap.org/soap/envelope/">
            <s:Body>
                <AuthnRequest xmlns="urn:oasis:names:tc:SAML:2.0:protocol"
                              ID="{request_id}"
                              Version="2.0"
                              IssueInstant="2023-10-01T00:00:00Z"
                              Destination="{self.destination_url}"
                              ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect">
                    <Issuer>{issuer}</Issuer>
                    <NameID>{name_id}</NameID>
                </AuthnRequest>
            </s:Body>
        </s:Envelope>"""
        
        return saml_request

    def encode_request(self, saml_request):
        encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        return encoded_request

    def send_request(self, user_info):
        saml_request = self.build_authn_request(user_info)
        encoded_request = self.encode_request(saml_request)
        
        payload = {
            'SAMLRequest': encoded_request
        }
        
        response = requests.post(self.destination_url, data=urlencode(payload))
        return response

